//! Model cache + on-demand generation.
//!
//! Two kinds of model:
//!  - **MNIST** — downloaded (ort's hosted test model; small I/O, proves the harness).
//!  - **relay** — synthetic `Y = X + X` models of controlled sizes (256 KB / 4 MB / 16 MB of
//!    f32 I/O), generated by `bench/tools/gen_models.py`. These unblock the tensor-size-
//!    dependent measurements MNIST can't: the O3 large-input copy crossover and the E2
//!    IoBinding zero-copy-output win. Generated on first use (needs `pip install onnx`).
use std::path::PathBuf;
use std::process::Command;

const MNIST_URL: &str = "https://cdn.pyke.io/0/pyke:ort-rs/example-models@0.0.0/mnist.onnx";
const HF_RESNET50_URL: &str =
    "https://huggingface.co/Xenova/resnet-50/resolve/main/onnx/model.onnx";

/// The shared model cache at `<repo>/bench/models` (resolved from this crate's dir).
fn bench_models_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("..")
        .join("bench")
        .join("models")
}

/// Resolve mnist.onnx: prefer the sibling `bench/models/` cache, else download locally.
pub fn ensure_mnist() -> std::io::Result<PathBuf> {
    let sibling = bench_models_dir().join("mnist.onnx");
    if sibling.exists() {
        return Ok(sibling);
    }
    let dir = PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("models");
    std::fs::create_dir_all(&dir)?;
    let path = dir.join("mnist.onnx");
    if !path.exists() {
        eprintln!("st-zrt-bench-c: downloading mnist.onnx");
        let status = Command::new("curl")
            .args(["-fsSL", "-o"])
            .arg(&path)
            .arg(MNIST_URL)
            .status()?;
        if !status.success() {
            return Err(std::io::Error::other("curl mnist.onnx failed"));
        }
    }
    Ok(path)
}

/// Resolve Xenova/resnet-50 from Hugging Face. This is a real ImageNet ONNX model with one
/// float input `[1,3,224,224]` and one logits output `[1,1000]`.
pub fn ensure_hf_resnet50() -> std::io::Result<PathBuf> {
    let sibling = bench_models_dir().join("hf_resnet50.onnx");
    if sibling.exists() {
        return Ok(sibling);
    }
    let dir = bench_models_dir();
    std::fs::create_dir_all(&dir)?;
    let path = dir.join("hf_resnet50.onnx");
    if !path.exists() {
        eprintln!("st-zrt-bench-c: downloading Xenova/resnet-50 ONNX from Hugging Face");
        let status = Command::new("curl")
            .args(["-fL", "-o"])
            .arg(&path)
            .arg(HF_RESNET50_URL)
            .status()?;
        if !status.success() {
            return Err(std::io::Error::other(
                "curl Xenova/resnet-50 model.onnx failed",
            ));
        }
    }
    Ok(path)
}

/// Resolve a synthetic relay model by label (`"256k"`, `"4m"`, `"16m"` → `relay_<label>.onnx`
/// in the shared cache). If absent, regenerate all sizes via `bench/tools/gen_models.py`
/// (requires `pip install onnx`).
pub fn ensure_relay(label: &str) -> std::io::Result<PathBuf> {
    ensure_relay_file(label, &format!("relay_{label}.onnx"))
}

/// Resolve a synthetic relay model with C stored as ONNX external data.
pub fn ensure_relay_external(label: &str) -> std::io::Result<PathBuf> {
    ensure_relay_file(label, &format!("relay_external_{label}.onnx"))
}

fn ensure_relay_file(label: &str, file_name: &str) -> std::io::Result<PathBuf> {
    let dir = bench_models_dir();
    std::fs::create_dir_all(&dir)?;
    let path = dir.join(file_name);
    if path.exists() {
        return Ok(path);
    }
    let script = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("..")
        .join("bench")
        .join("tools")
        .join("gen_models.py");
    eprintln!(
        "st-zrt-bench-c: generating relay models via {} (needs `pip install onnx`)",
        script.display()
    );
    let status = Command::new("python3").arg(&script).arg(&dir).status()?;
    if !status.success() {
        return Err(std::io::Error::other(format!(
            "gen_models.py failed (is `onnx` installed? path={})",
            script.display()
        )));
    }
    if !path.exists() {
        return Err(std::io::Error::other(format!(
            "relay model {file_name} not produced by generator (unknown label {label}?)"
        )));
    }
    Ok(path)
}
